package com.google.gson.internal.bind;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.JavaVersion;
import com.google.gson.internal.PreJava9DateFormatProvider;
import com.google.gson.internal.bind.util.ISO8601Utils;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.text.ParseException;
import java.text.ParsePosition;
import java.util.Locale;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class DefaultDateTypeAdapterTest {

  private DefaultDateTypeAdapter<Date> adapter;

  @BeforeEach
  public void setUp() throws Exception {
    // Use reflection to access private constructor: DefaultDateTypeAdapter(DateType<T> dateType, String datePattern)
    Class<?> clazz = DefaultDateTypeAdapter.class;

    // DateType is a package-private interface, create a minimal stub implementation via proxy or anonymous class
    @SuppressWarnings("unchecked")
    Class<Date> dateClass = (Class<Date>) Date.class;

    Class<?> dateTypeClass = null;
    for (Class<?> c : clazz.getDeclaredClasses()) {
      if ("DateType".equals(c.getSimpleName())) {
        dateTypeClass = c;
        break;
      }
    }
    // If DateType is not accessible, create a dummy interface for the test to satisfy constructor param
    Object dateType = new Object();
    // Try to find constructor with (DateType<T>, String)
    Constructor<?> constructor = null;
    for (Constructor<?> c : clazz.getDeclaredConstructors()) {
      Class<?>[] params = c.getParameterTypes();
      if (params.length == 2 && params[1] == String.class) {
        constructor = c;
        break;
      }
    }
    constructor.setAccessible(true);
    // Instantiate adapter with dummy dateType and datePattern "yyyy-MM-dd"
    adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd");
  }

  @Test
  public void testToString_withSimpleDateFormat() throws Exception {
    // Set dateFormats list to contain a SimpleDateFormat instance with pattern "yyyy-MM-dd"
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
    dateFormats.add(sdf);

    // Invoke toString
    String result = adapter.toString();

    // Expected: "DefaultDateTypeAdapter(yyyy-MM-dd)"
    assertEquals("DefaultDateTypeAdapter(yyyy-MM-dd)", result);
  }

  @Test
  public void testToString_withNonSimpleDateFormat() throws Exception {
    // Set dateFormats list to contain a DateFormat subclass that is not SimpleDateFormat
    Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
    dateFormatsField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);
    dateFormats.clear();

    // Create anonymous subclass of DateFormat overriding getClass().getSimpleName() indirectly by class name
    DateFormat customFormat = new DateFormat() {
      private static final long serialVersionUID = 1L;

      @Override
      public StringBuffer format(Date date, StringBuffer toAppendTo, java.text.FieldPosition fieldPosition) {
        return null;
      }

      @Override
      public Date parse(String source, ParsePosition pos) {
        return null;
      }

      @Override
      public String getClassSimpleName() {
        return "CustomFormat";
      }
    };
    // The getClass().getSimpleName() returns the anonymous class name, which is not "SimpleDateFormat"
    // So to test, just add this instance
    dateFormats.add(customFormat);

    // Invoke toString
    String result = adapter.toString();

    // Expected: "DefaultDateTypeAdapter(" + customFormat class simple name + ")"
    String expected = "DefaultDateTypeAdapter(" + customFormat.getClass().getSimpleName() + ")";
    assertEquals(expected, result);
  }
}
